# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from typing import List

class FileAccessControl:
    def __init__(self, db_name: str):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()

    def check_permission(self, user_id: int, file_path: str) -> bool:
        query = "SELECT access_level FROM permissions WHERE user_id=? AND file_path=?"
        self.cursor.execute(query, (user_id, file_path))
        result = self.cursor.fetchone()
        return True if result and result[0] >= 3 else False

    def get_file_contents(self, user_id: int, file_path: str) -> List[str]:
        if not self.check_permission(user_id, file_path):
            raise Exception("User does not have permission to read the file")

        query = "SELECT contents FROM files WHERE path=?"
        self.cursor.execute(query, (file_path,))
        result = self.cursor.fetchone()
        return [] if not result else str(result[0]).splitlines()

    def close_connection(self):
        self.conn.close()


if __name__ == "__main__":
    db_name = "document_management.db"

    access_control = FileAccessControl(db_name)

    user_id = 1
    file_path = "/path/to/file.txt"
    contents = access_control.get_file_contents(user_id, file_path)
    print(contents)

    access_control.close_connection()